package com.oyuki.product.controller; import com.oyuki.product.entity.Product; import com.oyuki.product.enums.ProductStatus; import com.oyuki.product.repository.ProductRepository; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/admin/products") public class AdminProductApprovalController { private final ProductRepository repo; public AdminProductApprovalController(ProductRepository r){repo=r;} @GetMapping("/pending") public List<Map<String,Object>> pending(){return repo.findAll().stream().filter(p->p.getStatus()==ProductStatus.PENDING_APPROVAL).map(this::map).toList();} @PatchMapping("/{id}/approve") public Map<String,Object> approve(@PathVariable Long id){Product p=repo.findById(id).orElseThrow();p.setStatus(ProductStatus.ACTIVE);return map(repo.save(p));} @PatchMapping("/{id}/reject") public Map<String,Object> reject(@PathVariable Long id){Product p=repo.findById(id).orElseThrow();p.setStatus(ProductStatus.REJECTED);return map(repo.save(p));} private Map<String,Object> map(Product p){return Map.of("id",p.getId(),"name",p.getName(),"ownerId",p.getOwner().getId(),"ownerName",p.getOwner().getFullName(),"status",p.getStatus(),"category",p.getCategory());} }